--
-- Table structure for table `rule_experiment`
--

DROP TABLE IF EXISTS `rule_experiment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rule_experiment` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `project_id` bigint DEFAULT NULL COMMENT '所属项目ID',
  `project_code` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所属项目编码',
  `experiment_code` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '实验编码',
  `experiment_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '实验名称',
  `description` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '说明',
  `routing_mode` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'RATIO' COMMENT '冠军挑战分流方式：RATIO/CONDITION',
  `test_routing_mode` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'CONDITION' COMMENT '测试组分流方式：RATIO/CONDITION',
  `condition_rule_code` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '条件分流规则编码',
  `request_key_path` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'requestId' COMMENT '请求唯一键路径',
  `test_exclusive` tinyint NOT NULL DEFAULT '1' COMMENT '测试组是否互斥',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：0-停用，1-启用',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_experiment_code` (`experiment_code`),
  KEY `idx_experiment_project` (`project_id`),
  KEY `idx_experiment_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='分流实验定义表';
/*!40101 SET character_set_client = @saved_cs_client */;

