--

DROP TABLE IF EXISTS `rule_experiment_execution_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rule_experiment_execution_log` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `experiment_id` bigint NOT NULL COMMENT '实验ID',
  `experiment_code` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '实验编码',
  `request_key` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '请求唯一键',
  `stage` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '阶段：PRODUCTION/TEST',
  `group_id` bigint DEFAULT NULL COMMENT '实验组ID',
  `group_code` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '实验组编码',
  `group_name` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '实验组名称',
  `group_type` varchar(32) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '实验组类型',
  `rule_code` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '执行规则编码',
  `route_reason` varchar(512) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '分流原因',
  `success` tinyint NOT NULL DEFAULT '1' COMMENT '执行结果',
  `input_params` text COLLATE utf8mb4_unicode_ci COMMENT '解析后入参',
  `output_result` text COLLATE utf8mb4_unicode_ci COMMENT '执行结果',
  `trace_info` longtext COLLATE utf8mb4_unicode_ci COMMENT '执行轨迹',
  `error_message` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '错误信息',
  `execute_time_ms` bigint DEFAULT NULL COMMENT '执行耗时',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '执行时间',
  PRIMARY KEY (`id`),
  KEY `idx_exp_log_request` (`experiment_id`,`request_key`,`stage`),
  KEY `idx_exp_log_group` (`group_id`,`create_time`),
  KEY `idx_exp_log_create` (`create_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='分流实验执行明细表';
