INSERT INTO `rule_function` VALUES (2,0,'GLOBAL','idCardGender','身份证提取性别','根据身份证号提取性别：女返回0，男返回1，未知返回-1','[{\"name\":\"idCard\",\"type\":\"STRING\",\"label\":\"身份证号\"}]','NUMBER','SCRIPT','if (idCard == null) {\n    return -1;\n}\nid = (\"\" + idCard).trim();\nif (id.matches(\"[0-9]{17}[0-9Xx]\")) {\n    sexText = id.substring(16, 17);\n} else if (id.matches(\"[0-9]{15}\")) {\n    sexText = id.substring(14, 15);\n} else {\n    return -1;\n}\nsexDigit = java.lang.Integer.parseInt(sexText);\nreturn sexDigit % 2 == 0 ? 0 : 1;','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),(3,0,'GLOBAL','idCardBirthDate','身份证提取出生日期','根据身份证号提取出生年月日，返回日期类型；无法识别时返回null','[{\"name\":\"idCard\",\"type\":\"STRING\",\"label\":\"身份证号\"}]','DATE','SCRIPT','if (idCard == null) {\n    return null;\n}\nid = (\"\" + idCard).trim();\nif (id.matches(\"[0-9]{17}[0-9Xx]\")) {\n    birthText = id.substring(6, 14);\n} else if (id.matches(\"[0-9]{15}\")) {\n    birthText = \"19\" + id.substring(6, 12);\n} else {\n    return null;\n}\ntry {\n    formatter = new java.text.SimpleDateFormat(\"yyyyMMdd\");\n    formatter.setLenient(false);\n    return formatter.parse(birthText);\n} catch (Exception ex) {\n    return null;\n}','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),(4,0,'GLOBAL','strLeft','字符串提取前N位','提取字符串前N位；长度不够返回全部字符','[{\"name\":\"text\",\"type\":\"STRING\",\"label\":\"字符串\"},{\"name\":\"n\",\"type\":\"NUMBER\",\"label\":\"位数\"}]','STRING','SCRIPT','if (text == null) {\n    return null;\n}\nif (n == null) {\n    return \"\";\n}\ns = \"\" + text;\nlimit = n.intValue();\nif (limit <= 0) {\n    return \"\";\n}\nif (s.length() <= limit) {\n    return s;\n}\nreturn s.substring(0, limit);','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),(5,0,'GLOBAL','strRight','字符串提取后N位','提取字符串后N位；长度不够返回全部字符','[{\"name\":\"text\",\"type\":\"STRING\",\"label\":\"字符串\"},{\"name\":\"n\",\"type\":\"NUMBER\",\"label\":\"位数\"}]','STRING','SCRIPT','if (text == null) {\n    return null;\n}\nif (n == null) {\n    return \"\";\n}\ns = \"\" + text;\nlimit = n.intValue();\nif (limit <= 0) {\n    return \"\";\n}\nlen = s.length();\nif (len <= limit) {\n    return s;\n}\nreturn s.substring(len - limit, len);','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),(6,0,'GLOBAL','idCardAge','身份证计算年龄','根据身份证出生日期计算年龄。currentDate可不传，默认当前时间；calcMode=YEAR按年相减，calcMode=FULL按年月日相减','[{\"name\":\"idCard\",\"type\":\"STRING\",\"label\":\"身份证号\"},{\"name\":\"currentDate\",\"type\":\"DATE\",\"label\":\"当前时间\"},{\"name\":\"calcMode\",\"type\":\"STRING\",\"label\":\"计算方式YEAR/FULL\"}]','NUMBER','SCRIPT','if (idCard == null) {\n    return -1;\n}\nid = (\"\" + idCard).trim();\nif (id.matches(\"[0-9]{17}[0-9Xx]\")) {\n    birthText = id.substring(6, 14);\n} else if (id.matches(\"[0-9]{15}\")) {\n    birthText = \"19\" + id.substring(6, 12);\n} else {\n    return -1;\n}\ntry {\n    formatter = new java.text.SimpleDateFormat(\"yyyyMMdd\");\n    formatter.setLenient(false);\n    birthDate = formatter.parse(birthText);\n} catch (Exception ex) {\n    return -1;\n}\nif (calcMode == null && currentDate instanceof java.lang.String) {\n    currentDateText = (\"\" + currentDate).trim();\n    if (currentDateText.equals(\"YEAR\") || currentDateText.equals(\"FULL\")) {\n        calcMode = currentDateText;\n        currentDate = null;\n    }\n}\nmode = calcMode == null ? \"FULL\" : (\"\" + calcMode).trim();\nif (currentDate == null) {\n    current = new java.util.Date();\n} else if (currentDate instanceof java.util.Date) {\n    current = currentDate;\n} else if (currentDate instanceof java.lang.String) {\n    currentText = (\"\" + currentDate).trim();\n    if (currentText.matches(\"[0-9]{8}\")) {\n        parseText = currentText;\n    } else if (currentText.matches(\"[0-9]{4}-[0-9]{2}-[0-9]{2}\")) {\n        parseText = currentText.substring(0, 4) + currentText.substring(5, 7) + currentText.substring(8, 10);\n    } else {\n        return -1;\n    }\n    try {\n        formatter = new java.text.SimpleDateFormat(\"yyyyMMdd\");\n        formatter.setLenient(false);\n        current = formatter.parse(parseText);\n    } catch (Exception ex) {\n        return -1;\n    }\n} else {\n    return -1;\n}\nage = current.getYear() - birthDate.getYear();\nif (age < 0) {\n    return -1;\n}\nif (mode.equals(\"YEAR\")) {\n    return age;\n}\nif (current.getMonth() < birthDate.getMonth() || (current.getMonth() == birthDate.getMonth() && current.getDate() < birthDate.getDate())) {\n    age = age - 1;\n}\nreturn age < 0 ? -1 : age;','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),(7,0,'GLOBAL','regexMatch','字符串正则匹配','字符串匹配正则表达式，匹配返回1，未匹配或表达式无效返回0','[{\"name\":\"text\",\"type\":\"STRING\",\"label\":\"字符串\"},{\"name\":\"regex\",\"type\":\"STRING\",\"label\":\"正则表达式\"}]','NUMBER','SCRIPT','if (text == null || regex == null) {\n    return 0;\n}\ntry {\n    return (\"\" + text).matches(\"\" + regex) ? 1 : 0;\n} catch (Exception ex) {\n    return 0;\n}','','','',1,'2026-07-07 00:34:31','2026-07-07 00:34:31'),(14,0,'GLOBAL','sum','序列求和','对列表、数组或 JSONPath 结果中的有效数字求和','[{\"name\":\"data\",\"label\":\"序列\",\"type\":\"OBJECT\",\"example\":[1,2,3]}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.AggregateBuiltinFunctions','sum',NULL,1,'2026-07-08 04:16:22','2026-07-08 04:16:22'),(15,0,'GLOBAL','count','序列计数','返回列表、数组或 JSONPath 结果的元素数量','[{\"name\":\"data\",\"label\":\"序列\",\"type\":\"OBJECT\",\"example\":[\"A\",\"B\",\"C\"]}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.AggregateBuiltinFunctions','count',NULL,1,'2026-07-08 04:16:22','2026-07-08 04:16:22'),(16,0,'GLOBAL','max','序列最大值','返回序列中有效数字的最大值','[{\"name\":\"data\",\"label\":\"序列\",\"type\":\"OBJECT\",\"example\":[3,9,2]}]','NUMBER','JAVA',NULL,'com.hengshucredit.rule.core.function.AggregateBuiltinFunctions','max',NULL,1,'2026-07-08 04:16:22','2026-07-08 04:16:22'),(17,0,'GLOBAL','min','序列最小值','返回序列中有效数字的最小值','[{\"name\":\"data\",\"label\":\"序列\",\"type\":\"OBJECT\",\"example\":[3,9,2]}]','NUMBER','JAVA',