INSERT INTO `rule_function_version` VALUES (1,1,1,'{\"createTime\":1783355671000,\"description\":\"身份证提取出生日期\\n\\n参数：idCard（STRING）\\n返回类型：DATE 或 OBJECT\",\"funcCode\":\"idCardBirthDate\",\"funcName\":\"身份证生日提取\",\"id\":1,\"implBeanName\":\"\",\"implClass\":\"\",\"implMethod\":\"\",\"implScript\":\"if (idCard == null) {\\r\\n    return null;\\r\\n}\\r\\n\\r\\nid = idCard.toString().trim();\\r\\n\\r\\nif (id.matches(\\\"^[0-9]{17}[0-9Xx]$\\\")) {\\r\\n    birthText = id.substring(6, 14);\\r\\n} else if (id.matches(\\\"^[0-9]{15}$\\\")) {\\r\\n    birthText = \\\"19\\\" + id.substring(6, 12);\\r\\n} else {\\r\\n    return null;\\r\\n}\\r\\n\\r\\ntry {\\r\\n    formatter = new java.text.SimpleDateFormat(\\\"yyyyMMdd\\\");\\r\\n    formatter.setLenient(false);\\r\\n    return formatter.parse(birthText);\\r\\n} catch (Exception e) {\\r\\n    return null;\\r\\n}\",\"implType\":\"SCRIPT\",\"paramsJson\":\"[{\\\"name\\\":\\\"idCard\\\",\\\"type\\\":\\\"STRING\\\",\\\"label\\\":\\\"身份证号\\\"}]\",\"projectId\":0,\"returnType\":\"DATE\",\"scope\":\"GLOBAL\",\"status\":1,\"updateTime\":1783355671000}','create',NULL,'2026-07-07 00:34:31');
