DROP TABLE IF EXISTS `rule_list_library`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rule_list_library` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `project_id` bigint NOT NULL DEFAULT '0' COMMENT '所属项目ID，0 表示全局',
  `scope` varchar(16) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PROJECT' COMMENT '作用范围：GLOBAL/PROJECT',
  `list_code` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '名单库编码',
  `list_name` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '名单库名称',
