DROP TABLE IF EXISTS `rule_runtime_call_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rule_runtime_call_log` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `module_type` varchar(32) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '模块类型：DATASOURCE/DATABASE/LIST/MODEL',
  `action_type` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '动作类型：API_INVOKE/AUTH_TEST/QUERY/EXECUTE等',
  `project_id` bigint DEFAULT NULL COMMENT '项目ID',
  `project_code` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '项目编码',
  `target_ref_id` bigint DEFAULT NULL COMMENT '目标配置ID',
  `target_code` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标编码',
  `target_name` varchar(128) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标名称',
  `success` tinyint NOT NULL DEFAULT '1' COMMENT '是否成功：0-失败，1-成功',
  `request_method` varchar(16) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '请求方法',
  `request_url` varchar(1024) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '请求地址',
  `request_headers` text COLLATE utf8mb4_unicode_ci COMMENT '请求头JSON（敏感值脱敏）',
  `request_params` longtext COLLATE utf8mb4_unicode_ci COMMENT '请求入参JSON',
  `request_body` longtext COLLATE utf8mb4_unicode_ci COMMENT '请求体JSON或文本',
  `response_status` int DEFAULT NULL COMMENT '响应状态码',
  `response_body` longtext COLLATE utf8mb4_unicode_ci COMMENT '响应内容JSON或文本',
  `error_message` varchar(2048) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '错误信息',
  `cost_time_ms` bigint DEFAULT NULL COMMENT '耗时毫秒',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '发生时间',
  PRIMARY KEY (`id`),
  KEY `idx_runtime_log_module_time` (`module_type`,`create_time`),
  KEY `idx_runtime_log_target_time` (`target_ref_id`,`create_time`),
  KEY `idx_runtime_log_success` (`success`,`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=107 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='运行时调用诊断日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

